import{_ as a,o as e,c as o,a2 as i}from"./chunks/framework.DIMps2S2.js";const p=JSON.parse('{"title":"如何选择入金方式","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"deposit/how-to-choose-deposit-method.md","filePath":"zh-CN/deposit/how-to-choose-deposit-method.md"}'),r={name:"deposit/how-to-choose-deposit-method.md"};function d(h,t,l,s,n,c){return e(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="如何选择入金方式" tabindex="-1">如何选择入金方式 <a class="header-anchor" href="#如何选择入金方式" aria-label="Permalink to &quot;如何选择入金方式&quot;">​</a></h1><p>根据账户类型、资金紧急程度和手续费需求，选择最合适的入金方式。</p><hr><h2 id="第一步-确认账户类型" tabindex="-1">第一步：确认账户类型 <a class="header-anchor" href="#第一步-确认账户类型" aria-label="Permalink to &quot;第一步：确认账户类型&quot;">​</a></h2><p>长桥香港账户和新加坡账户支持的入金方式不同：</p><ul><li><strong>长桥香港账户</strong> → 见下方<a href="#香港账户">香港账户</a></li><li><strong>长桥新加坡账户</strong> → 见下方<a href="#新加坡账户">新加坡账户</a></li></ul><p>如果不确定账户类型，进入「资产」→ 查看账户标识（「HK」为香港账户，「SG」为新加坡账户）。</p><hr><h2 id="香港账户" tabindex="-1">香港账户 <a class="header-anchor" href="#香港账户" aria-label="Permalink to &quot;香港账户&quot;">​</a></h2><h3 id="需要即时到账" tabindex="-1">需要即时到账 <a class="header-anchor" href="#需要即时到账" aria-label="Permalink to &quot;需要即时到账&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方式</th><th>条件</th><th>手续费</th></tr></thead><tbody><tr><td><a href="/wiki/deposit/hk-methods/bank-securities-transfer">银证转账</a></td><td>持有参与银证通的香港银行卡（如渣打、恒生、工银亚洲等）</td><td>免费</td></tr><tr><td><a href="/wiki/deposit/hk-methods/edda">eDDA</a></td><td>已完成 eDDA 绑定</td><td>免费</td></tr></tbody></table><blockquote><p>遭遇追缴保证金（Margin Call）时，优先选择上述即时到账方式，避免因资金未到账被强平。</p></blockquote><h3 id="不需要即时-希望免手续费" tabindex="-1">不需要即时，希望免手续费 <a class="header-anchor" href="#不需要即时-希望免手续费" aria-label="Permalink to &quot;不需要即时，希望免手续费&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方式</th><th>预计到账时间</th><th>备注</th></tr></thead><tbody><tr><td><a href="/wiki/deposit/hk-methods/fps">FPS 转数快</a></td><td>约 2 小时</td><td>免费，需使用长桥专属 FPS 二维码</td></tr><tr><td><a href="/wiki/deposit/hk-methods/bank-securities-transfer">银证转账</a></td><td>即时</td><td>同上，首选</td></tr></tbody></table><h3 id="持有境外银行卡-无香港银行账户" tabindex="-1">持有境外银行卡，无香港银行账户 <a class="header-anchor" href="#持有境外银行卡-无香港银行账户" aria-label="Permalink to &quot;持有境外银行卡，无香港银行账户&quot;">​</a></h3><p>选择<a href="/wiki/deposit/电汇入金">电汇入金</a>，通过境外银行向长桥香港收款账户汇款。预计到账时间约 2–5 个工作日，手续费由汇款银行收取。</p><hr><h2 id="新加坡账户" tabindex="-1">新加坡账户 <a class="header-anchor" href="#新加坡账户" aria-label="Permalink to &quot;新加坡账户&quot;">​</a></h2><h3 id="sgd-新加坡元" tabindex="-1">SGD（新加坡元） <a class="header-anchor" href="#sgd-新加坡元" aria-label="Permalink to &quot;SGD（新加坡元）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方式</th><th>预计到账时间</th><th>手续费</th></tr></thead><tbody><tr><td><a href="/wiki/deposit/sg-methods/paynow">PayNow</a></td><td>最快 5 分钟</td><td>免费</td></tr><tr><td><a href="/wiki/deposit/sg-methods/dda-authorization">DDA 自动扣款</a></td><td>实时</td><td>免费</td></tr><tr><td><a href="/wiki/deposit/网银与电汇入金">网银转账</a></td><td>1–3 个工作日</td><td>银行可能收费</td></tr></tbody></table><ul><li>如果是<strong>首次入金</strong>，PayNow 最快、无需提前设置</li><li>如果<strong>频繁入金</strong>，建议完成 DDA 绑定（支持 DBS/POSB、UOB、OCBC、Maybank、HSBC SG），之后每次实时到账</li></ul><h3 id="usd-美元-或-hkd-港元" tabindex="-1">USD（美元）或 HKD（港元） <a class="header-anchor" href="#usd-美元-或-hkd-港元" aria-label="Permalink to &quot;USD（美元）或 HKD（港元）&quot;">​</a></h3><p>使用 <a href="/wiki/deposit/sg-methods/wise">Wise</a> 或<a href="/wiki/deposit/网银与电汇入金">网银转账</a>，预计到账时间约 1–3 个工作日。</p><blockquote><p>Wise 入金需上传账户证明文件（含姓名、账户号码及 Wise logo）。</p></blockquote><hr><h2 id="账户姓名要求与入金限制" tabindex="-1">账户姓名要求与入金限制 <a class="header-anchor" href="#账户姓名要求与入金限制" aria-label="Permalink to &quot;账户姓名要求与入金限制&quot;">​</a></h2><ul><li>入金账户姓名须与长桥账户姓名<strong>完全一致</strong>；非本人账户汇款会被拒绝，退款手续费由客户承担</li><li><strong>不接受</strong>大陆银行卡直接入金，也不接受信用卡入金</li><li>如有多笔汇款，请针对每笔单独填写存款通知</li></ul><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/deposit/methods-overview">入金方式总览</a> — 所有入金方式的到账时间与手续费一览表</li><li><a href="/wiki/margin/how-to-respond-to-margin-call">如何应对追加保证金通知</a> — 紧急入金场景的处理步骤</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/account/account-faq">账户常见问题</a></li><li><a href="/wiki/deposit/methods-overview">入金方式</a></li><li><a href="/wiki/margin/how-to-respond-to-margin-call">如何应对追加保证金通知</a></li></ul>',32)])])}const b=a(r,[["render",d]]);export{p as __pageData,b as default};
